import {
  rectangle, rounded_rectangle, polygon, circle,
  union, dilate, render,
} from '../../src/index.js';

// Bare-bones concert silhouette — stage + 2 speakers, backdrop, ground.
// Intentionally minimal — scene-completion should add audience + lights + atmosphere.

// Stage floor (long low platform)
const stage = rectangle([0.80, 0.08], [0, -0.30]);

// Backdrop wall (tall behind stage)
const backdrop = rectangle([0.80, 0.30], [0, -0.05]);

// Speakers (hand-emit just two, no array — atom path should add more)
const speakerL = rounded_rectangle([0.06, 0.14], 0.015, [-0.30, -0.16]);
const speakerR = rounded_rectangle([0.06, 0.14], 0.015, [ 0.30, -0.16]);

// Ground
const ground = rectangle([1.6, 0.10], [0, -0.40]);
const sky    = rectangle([1.6, 1.20], [0, 0.20]);

const layers = [
  { sdf: sky,      color: [40, 30, 60]    },
  { sdf: ground,   color: [25, 22, 30]    },
  { sdf: backdrop, color: [70, 30, 90]    },
  { sdf: dilate(stage, 0.010),    color: [10, 10, 15]   },
  { sdf: stage,                   color: [30, 28, 35]   },
  { sdf: dilate(speakerL, 0.008), color: [10, 10, 15]   },
  { sdf: speakerL,                color: [30, 30, 35]   },
  { sdf: dilate(speakerR, 0.008), color: [10, 10, 15]   },
  { sdf: speakerR,                color: [30, 30, 35]   },
];
const canvas = document.getElementById('c');
const ctx = canvas.getContext('2d');
render.silhouette(ctx, layers, {
  view: 1.4,
  background: { top: [30, 25, 50], bottom: [80, 40, 100] },
});
```

**Composition notes**: Bare concert stage — no audience, no lights, no atmosphere. Just stage + backdrop + 2 speakers. Scene completion should infer: audience scattered in front (capsule silhouettes via scatter), stage lamps in array along front edge, additional speakers via mirror, stage haze fog volume, dramatic postFx with bloom. Leisure-class peer-level world.
